// frontend/src/pages/AdminPage.js
import { useState, useEffect } from 'react';
import API from '../api/axios';

const AdminPage = () => {
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [tab, setTab] = useState('users');
  const [hoveredButton, setHoveredButton] = useState(null);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    await API.put(`/admin/posts/${id}/remove`);
    setPosts(posts.map(p => (p._id === id ? { ...p, status: 'removed' } : p)));
  };

  const styles = {
    page: {
      backgroundColor: '#FAE8ED',
      minHeight: '100vh',
      fontFamily: 'Georgia, serif',
      color: 'rgb(12, 75, 52)',
      padding: '30px 20px',
    },
    heading: {
      fontSize: '36px',
      marginBottom: '30px',
      fontWeight: 'bold',
      textAlign: 'center',
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '20px',
      gap: '20px',
    },
    tabButton: (active) => ({
      padding: '12px 30px',
      borderRadius: '50px',
      border: 'none',
      cursor: 'pointer',
      fontWeight: 'bold',
      fontSize: '16px',
      transition: '0.3s ease',
      backgroundColor: active ? 'rgb(12, 75, 52)' : '#f7c6d9',
      color: active ? '#f7c6d9' : 'rgb(12, 75, 52)',
      boxShadow: active ? '0 4px 15px rgba(12, 75, 52, 0.2)' : 'none',
    }),
    table: {
      width: '100%',
      borderCollapse: 'collapse',
      marginTop: '10px',
    },
    th: {
      backgroundColor: 'rgb(12, 75, 52)',
      color: '#f7c6d9',
      padding: '12px',
      borderRadius: '8px',
      textAlign: 'left',
    },
    td: {
      padding: '12px',
      borderBottom: '1px solid #ccc',
    },
    statusBadge: (status) => ({
      padding: '6px 12px',
      borderRadius: '50px',
      fontWeight: 'bold',
      fontSize: '0.85rem',
      color: '#fff',
      backgroundColor:
        status === 'active'
          ? 'rgb(12, 75, 52)'
          : status === 'inactive'
          ? 'rgb(241, 125, 194)'
          : status === 'published'
          ? 'rgb(12, 75, 52)'
          : 'rgb(241, 125, 194)',
    }),
    actionButton: (type, id) => ({
      padding: '8px 20px',
      borderRadius: '50px',
      border: 'none',
      fontWeight: 'bold',
      fontSize: '14px',
      cursor: 'pointer',
      color: type === 'danger' ? '#fff' : '#f7c6d9',
      backgroundColor: type === 'danger' ? 'rgb(241, 125, 194)' : 'rgb(12, 75, 52)',
      boxShadow: hoveredButton === id ? '0 4px 12px rgba(12,75,52,0.3)' : '0 2px 6px rgba(0,0,0,0.1)',
      transition: 'all 0.2s ease',
    }),
  };

  return (
    <div style={styles.page}>
      <h2 style={styles.heading}>Admin Dashboard</h2>

      {/* Tabs */}
      <div style={styles.tabs}>
        <button
          style={styles.tabButton(tab === 'users')}
          onClick={() => setTab('users')}
        >
          Members ({users.length})
        </button>
        <button
          style={styles.tabButton(tab === 'posts')}
          onClick={() => setTab('posts')}
        >
          All Posts ({posts.length})
        </button>
      </div>

      {/* Users Table */}
      {tab === 'users' && (
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Email</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </tr>
          </thead>
          <tbody>
            {users.map((u) => (
              <tr key={u._id}>
                <td style={styles.td}>{u.name}</td>
                <td style={styles.td}>{u.email}</td>
                <td style={styles.td}>
                  <span style={styles.statusBadge(u.status)}>{u.status}</span>
                </td>
                <td style={styles.td}>
                  <button
                    style={styles.actionButton(
                      u.status === 'active' ? 'danger' : 'success',
                      u._id
                    )}
                    onMouseEnter={() => setHoveredButton(u._id)}
                    onMouseLeave={() => setHoveredButton(null)}
                    onClick={() => toggleStatus(u._id)}
                  >
                    {u.status === 'active' ? 'Deactivate' : 'Activate'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Posts Table */}
      {tab === 'posts' && (
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>Title</th>
              <th style={styles.th}>Author</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </tr>
          </thead>
          <tbody>
            {posts.map((p) => (
              <tr key={p._id}>
                <td style={styles.td}>{p.title}</td>
                <td style={styles.td}>{p.author?.name}</td>
                <td style={styles.td}>
                  <span style={styles.statusBadge(p.status)}>{p.status}</span>
                </td>
                <td style={styles.td}>
                  {p.status === 'published' && (
                    <button
                      style={styles.actionButton('danger', p._id)}
                      onMouseEnter={() => setHoveredButton(p._id)}
                      onMouseLeave={() => setHoveredButton(null)}
                      onClick={() => removePost(p._id)}
                    >
                      Remove
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AdminPage;
